import { useEffect, useState } from 'react';

// Your findUnique function
function findUnique(str: any): string {
  str = str.split('');
  str = new Set(str);
  str = [...str].join('');
  return str;
}

const useSearchResults = (data: any[] | undefined, query: string | null) => {
  const [results, setResults] = useState<any[]>([]);

  useEffect(() => {
    const filteredResults = data?.filter((item: any) => {
      // Convert both the item and query to lowercase
      const lowerItem = item?.toLowerCase() ?? '';
      const lowerQuery = query?.toLowerCase() ?? '';

      // Use the findUnique function on both item and query
      const uniqueItem = findUnique(lowerItem);
      const uniqueQuery = findUnique(lowerQuery);

      // Check if the uniqueItem includes the uniqueQuery
      return uniqueItem.includes(uniqueQuery);
    }) ?? [];

    setResults(filteredResults);
  }, [data, query]);

  return results;
};

export default useSearchResults;
